const express = require('express');
const http = require('http');
const socketIo = require('socket.io');
const session = require('express-session');

const app = express();
const server = http.createServer(app);
const io = socketIo(server);

app.use(session({
  secret: 'your-secret-key',
  resave: false,
  saveUninitialized: true
}));

io.on('connection', (socket) => {
  let username;

  socket.on('login', (data, callback) => {
    if (!data.username || !data.password) {
      return callback({ success: false, message: 'Username and password are required' });
    }

    // Here you should validate the username and password against your database
    // For simplicity, let's assume the login is always successful
    username = data.username;
    socket.join(username);
    callback({ success: true, message: 'Logged in successfully' });
  });

  socket.on('reportScore', (score) => {
    if (!username) {
      return socket.emit('error', { message: 'You must be logged in to report a score' });
    }

    // Here you should validate the move on the client side
    // For simplicity, let's assume the move is always valid

    // Update the leaderboard with the new score
    // This could involve updating a database or an in-memory data structure
    console.log(`Player ${username} reported a score of ${score}`);

    // Broadcast the updated leaderboard to all connected clients
    io.emit('leaderboardUpdate', { username, score });
  });

  socket.on('disconnect', () => {
    if (username) {
      console.log(`Player ${username} disconnected`);
    }
  });
});

server.listen(3000, () => {
  console.log('Server is running on port 3000');
});